# Demo4 (key=7) is the SAME input as test. Let me understand it as nested brackets.
# Identify distinct colored shapes by color in input demo4
inp=data["demos"][1]["input"]; out=data["demos"][1]["output"]
from collections import defaultdict
def cells_by_color(g):
    d=defaultdict(list)
    for r in range(len(g)):
        for c in range(len(g[0])):
            if g[r][c]!=0: d[g[r][c]].append((r,c))
    return d
ci=cells_by_color(inp); co=cells_by_color(out)
for col in sorted(set(list(ci)+list(co))):
    print("color",col,"IN:",ci.get(col),"\n         OUT:",co.get(col))
